26→suspend inline fun <reified EVENT : Any> Dispatcher.awaitEvent(): EVENT = suspendCancellableCoroutine { continuation ->
27→    val listener = object : GenericEventBusListener<EVENT>(EVENT::class) {
28→        override fun handleEvent(event: EVENT) {
29→            unregister(this)
30→            if (!continuation.isActive) {
31→                AppLog.w(AppLog.T.UTILS, "Listener for ${EVENT::class} invoked after cancellation")
32→                return
33→            }
34→            continuation.resume(event)
35→        }
36→    }
37→    register(listener)
38→
39→    continuation.invokeOnCancellation {
40→        unregister(listener)
41→    }
42→}
