44→inline fun <reified EVENT : Any> Dispatcher.observeEvents(): Flow<EVENT> = callbackFlow {
45→    val listener = object : GenericEventBusListener<EVENT>(EVENT::class) {
46→        override fun handleEvent(event: EVENT) {
47→            trySend(event)
48→                .onFailure {
49→                    AppLog.w(AppLog.T.UTILS, "Failure to emit EventBus's event $event as Flow, ${it?.toString()}")
50→                }
51→        }
52→    }
53→    register(listener)
54→
55→    awaitClose {
56→        unregister(listener)
57→    }
58→}
