60→abstract class GenericEventBusListener<EVENT : Any>(private val kClass: KClass<EVENT>) {
61→    @Subscribe(threadMode = ThreadMode.MAIN)
62→    @Suppress("unused")
63→    fun onEvent(event: EVENT) {
64→        // Since generic types are suppressed at runtime, this listener will be registered using the type Object
65→        // But using the reified EVENT type, we can compare the class and ignore unwanted events
66→        if (event::class != kClass) return
67→
68→        handleEvent(event)
69→    }
70→
71→    abstract fun handleEvent(event: EVENT)
72→}
